mapper.select:
SELECT DISTINCT a.schedule_task_id
FROM action a
INNER JOIN schedule_task st ON a.schedule_task_id = st.id
WHERE st.laboratory_id = #{labId}

    AND st.enable = #{enable}


    AND a.device_type = #{deviceType}


    AND a.device_id = #{deviceId}


    AND a.command_line = #{commandLine}

SELECT * FROM action WHERE schedule_task_id IN
#{id}
ORDER BY action_group_id, id
